import json
import requests

# Define the services, routes, and upstream targets
services = {
    "service1": {
        "url": "http://localhost:8000"
    },
    "service2": {
        "url": "http://localhost:9000"
    }
}
routes = [
    {
        "protocols": ["http", "https"],
        "methods": ["GET", "POST"],
        "paths": ["/path1"]
    },
    {
        "protocols": ["http", "https"],
        "methods": ["GET", "POST"],
        "paths": ["/path2"]
    }
]
upstream_targets = [
    {"target": "service1"},
    {"target": "service2"}
]

# POST the configuration to Kong's admin endpoint
response = requests.post("http://localhost:8001/services", json=services)
if response.status_code == 201:
    print("Services created successfully")
else:
    print(f"Failed to create services, status code: {response.status_code}")

for route in routes:
    # POST the route configuration to Kong's admin endpoint
    response = requests.post("http://localhost:8001/routes", json=route)
    if response.status_code == 201:
        print(f"Route {route['paths'][0]} created successfully")
    else:
        print(f"Failed to create route {route['paths'][0]}, status code: {response.status_code}")

for target in upstream_targets:
    # POST the upstream target configuration to Kong's admin endpoint
    response = requests.post("http://localhost:8001/upstreams", json=target)
    if response.status_code == 201:
        print(f"Upstream target {target['target']} created successfully")
    else:
        print(f"Failed to create upstream target {target['target']}, status code: {response.status_code}")